INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6acbf4ac-moex-00018', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於行政機關之管轄，下列敘述何者正確？', '["行政機關對事件管轄權之有無，應依職權調查；其認無管轄權者，應即移送司法機關，並通知 當事人", "行政機關得依法規將其權限之一部分，委任民間團體或個人辦理", "行政機關因業務上之需要，得依法規將其權限之一部分，委託不相隸屬之行政機關執行之", "數行政機關於管轄權有爭議時，應由司法機關指定管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00019', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於行政契約之敘述，下列何者正確？', '["行政契約與行政處分乃不同性質之行政作用，故行政機關有作成行政處分權限時，即不可再締 結行政契約", "國民住宅之買賣契約屬於取代行政處分之行政契約", "行政契約原則上是屬於要式行為", "行政契約依約定內容履行將侵害第三人之權利者，應經該第三人書面或口頭之同意，始生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00020', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '主管機關建議農民甲停種作物並輔導休耕，甲表示不同意，依行政程序法規定，該機關應如何為 適法之處理？', '["以甲為相對人作成行政處分，命其休耕", "對甲裁處罰鍰，並於甲休耕前，得連續處罰", "應派員親至當地強制執行休耕", "應停止繼續建議或輔導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00021', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於行政罰管轄機關及裁處程序之敘述，下列何者正確？', '["一行為違反數個行政法上義務而應處罰鍰，數機關均有管轄權者，由處理在先之機關管轄", "行政機關對現行違反行政法上義務之行為人，得即時制止其行為", "一行為違反同一行政法上義務，數機關均有管轄權者，由其共同上級機關管轄", "得沒入之物，得扣留之，行政機關為沒入之裁處前，應舉行聽證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00022', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於行政執行之敘述，下列何者錯誤？', '["行政機關依法作成行政處分，課予人民義務，不表示即可以強制手段貫徹之，因此行政執行須 另有法律依據，且須符合動用強制手段之法定要件與程序", "行政機關於動用強制手段前，須於處分書或另以書面限定相當之履行期限，並告知不履行之後果", "行政強制措施若涉及剝奪人民身體自由者，例如管收，基於憲法第8條之規定，須經法院始得 為之", "行為或不行為義務之執行，由原處分機關或該管行政機關為之；公法上金錢給付義務逾期不履 行者，亦同 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00023', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者正確？', '["申請人對於政府機關就其申請提供政府資訊所為之決定不服者，不得提起行政救濟", "政府機關提供政府資訊時，得按申請政府資訊之用途，向申請人收取費用", "申請政府機關提供政府資訊，以具有中華民國國籍者為限", "人民請求政府資訊公開，以維護其法律上利益有必要者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00024', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '依司法實務見解，受理訴願機關撤銷原行政處分之全部時，下列敘述何者正確？', '["訴願管轄機關得逕為更不利益之變更決定，如發回原行政處分機關另為處分時亦得為更不利益 之處分", "訴願管轄機關不得為更不利益之變更決定，但發回原行政處分機關另為處分時得為更不利益之 處分", "訴願管轄機關得逕為更不利益之變更決定，但發回原行政處分機關另為處分時不得為更不利益 之處分", "訴願管轄機關不得逕為更不利益之變更決定，如發回原處分行政機關另為處分時亦不得為更不 利益之處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00025', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於訴願審議委員會之敘述，下列何者正確？', '["各機關辦理訴願事件，應設訴願審議委員會，組成人員以具有法制專長者為限", "訴願審議委員會委員，由本機關高級職員及遴聘社會公正人士、學者、專家擔任之；其中社會 公正人士、學者、專家人數不得少於三分之一", "訴願決定應經訴願審議委員會會議之決議，其決議以委員三分之二之出席，出席委員過半數之 同意行之", "訴願審議委員會主任委員或委員對於訴願事件有利害關係者，應自行迴避，不得參與審議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00026', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '下列何者不得提起行政訴訟之確認訴訟？', '["公立學校教師經學校解聘後，對該解聘不服", "人民對於違反專屬管轄之行政處分不服", "違建已倒塌，所有權人對該建物拆除處分不服", "政府採購案未得標廠商對決標處分不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL),
  ('promotion-6acbf4ac-moex-00027', 'promotion-6acbf4ac', 'promotion-6acbf4ac-moex-114-3082b5f1', 'sub-promotion-6acbf4ac-02', NULL, 'single_choice', '關於行政訴訟第一審裁判之敘述，下列何者正確？', '["法官非參與裁判基礎之辯論者，不得參與裁判", "各種獨立之攻擊或防禦方法，達於可為裁判之程度者，行政法院應為終局判決", "當事人兩造於言詞辯論期日，無正當理由均不到場者，行政法院不得逕為判決", "行政法院對於行政機關依裁量權所為之行政處分，均不得予以撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:47+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "145", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "警察行政"}'::jsonb, NULL)
